#include <stdio.h>

int main() {
  printf("Hello, World!\n");
  return 0;
}
// Output:
// Hello, World!

#include <stdio.h>

#define PI 3.14159
#define SQUARE(x) ((x) * (x))

int main() {
  float radius = 5.0;
  float area = PI * SQUARE(radius);
  printf("Circle area: %.2f\n", area);
  return 0;
}
// Output:
// Circle area: 78.54

#include <stdio.h>

#define DEBUG

int main() {
  #ifdef DEBUG
    printf("Debug mode is ON\n");
  #else
    printf("Debug mode is OFF\n");
  #endif
  return 0;
}
// Output:
// Debug mode is ON

// myheader.h
#ifndef MYHEADER_H
#define MYHEADER_H

int add(int a, int b) {
  return a + b;
}

#endif

// main.c
#include <stdio.h>
#include "myheader.h"

int main() {
  printf("Sum: %d\n", add(3, 4));
  return 0;
}
// Output:
// Sum: 7

#include <stdio.h>

#define SQUARE(x) x * x // Səhv: Qapaqlar olmadan

int main() {
  int result = SQUARE(2 + 3);
  printf("Result: %d\n", result);
  return 0;
}
// Output:
// Result: 11 (Gözlənirdi: 25)

